  'guiyang/sourfish': ('Ekşi Çorbalı Balık', 'Domates ve ekşi mayalı kırmızı çorbada pişen balık, Guizhou\'nun imza yemeğidir.'),
  'guiyang/waterfall': ('Huangguoshu Şelalesi', 'Asya\'nın en büyük şelalelerinden biri, gürül gürül dökülerek gökkuşakları yaratır.'),
  'guiyang/miao': ('Miao Kültürü', 'Gümüş başlıklı Miao halkının şenlikleri ve nakışları dağ köylerini renklendirir.'),
  'changchun/film': ('Film Şehri', 'Çin sinemasının doğduğu stüdyolar burada; \'Doğu\'nun Hollywood\'u\' diye anılır.'),
  'changchun/car': ('Otomobil Şehri', 'Çin\'in ilk yerli otomobili bu fabrikalardan çıktı; ülkenin araba başkentidir.'),
  'changchun/palace': ('Kukla Mançu Sarayı', 'Son imparatorun yaşadığı saray, dalgalı bir tarihin sessiz tanığıdır.'),
  'changchun/snow': ('Kış ve Kar', 'Uzun, bembeyaz kışlarıyla şehir, buz heykelleri ve kayak pistleriyle parlar.'),
  'xining/lake': ('Qinghai Gölü', 'Çin\'in en büyük tuz gölü, yazın çevresini saran sarı kolza tarlalarıyla ünlüdür.'),
  'xining/monastery': ('Kumbum Manastırı', 'Tibet Budizminin altı büyük manastırından biri; tereyağı heykelleriyle meşhurdur.'),
  'xining/flower': ('Kolza Çiçeği', 'Temmuzda plato altın sarısı kolza tarlalarıyla ufka kadar kaplanır.'),
  'xining/lamb': ('Yak ve Kuzu', 'Hui ve Tibet mutfağının elle çekilmiş eriştesi ve kuzu şişi yaylanın lezzetidir.'),
  'guilin/karst': ('Li Nehri Dağları', 'Sis içinde yükselen kireçtaşı tepeler, \'20 yuan\'lık banknotun manzarasıdır.'),
  'guilin/elephant': ('Fil Hortumu Tepesi', 'Hortumunu nehre daldıran fil biçimli kaya, şehrin sevilen simgesidir.'),
  'guilin/terrace': ('Longji Pirinç Terasları', 'Dağ yamaçlarını saran \'Ejderha Sırtı\' terasları, asırlık emeğin merdivenidir.'),
  'guilin/osmanthus': ('Tatlı Osmanthus', 'Adı \'osmanthus ormanı\' demektir; sonbaharda şehir tatlı çiçek kokusuna boğulur.'),
  'wenzhou/merchant': ('Tüccar Ruhu', '\'Çin\'in Yahudileri\' denen Wenzhoulu girişimciler dünyaya yayılmış iş ağı kurar.'),
  'wenzhou/shoe': ('Ayakkabı ve Deri', 'Dünyanın deri ayakkabılarının büyük kısmı bu fabrika şehrinden çıkar.'),
  'wenzhou/mountain': ('Yandang Dağları', 'Şelaleleri ve sivri zirveleriyle ünlü dağlar, \'denizin üstündeki ilk dağ\' sayılır.'),
  'wenzhou/seafood': ('Deniz Ürünleri', 'Doğu Çin Denizi\'nin kalamar, deniz tarağı ve balığı yerel sofranın temelidir.'),
  'tangshan/memorial': ('Deprem Anıtı', '1976 büyük depreminin anısına kurulan park, yeniden doğan şehrin simgesidir.'),
  'tangshan/coal': ('Kömür ve Çelik', 'Çin\'in ilk modern kömür madeni ve demiryolu burada açıldı; sanayinin beşiğidir.'),
  'tangshan/ceramic': ('Tangshan Seramiği', '\'Kuzeyin porselen şehri\'; kemik porseleni masaları zarafetle donatır.'),
  'tangshan/lake': ('Nanhu Parkı', 'Eski maden çukurundan doğan göl-park, şehrin yeşil ciğeri oldu.'),
  'anshan/steel': ('Çelik Şehri', 'Çin\'in en büyük çelik kombinası burada kuruldu; ülkenin \'çelik başkenti\'dir.'),
  'anshan/jade': ('Xiuyan Yeşimi', 'Dünyanın en büyük yeşim heykeli buradadır; şehir Çin\'in yeşim diyarıdır.'),
  'anshan/mountain': ('Qianshan Dağı', '\'Bin Lotus Zirvesi\' dağı, tapınakları ve kayalarıyla kuzeyin kutsal dorukudur.'),
  'anshan/spring': ('Tanggangzi Kaplıcası', 'Bin yıldır şifa aranan sıcak su kaplıcaları imparatorları bile ağırladı.'),
  'linyi/market': ('Toptan Çarşı', 'Kuzey Çin\'in en büyük toptan ticaret merkezi, mallarını tüm ülkeye dağıtır.'),
  'linyi/brush': ('Wang Xizhi', 'Çin\'in \'kaligrafi bilgesi\' Wang Xizhi burada doğdu; şehir mürekkebin diyarıdır.'),
  'linyi/mountain': ('Mengshan Dağı', 'Şandong\'un ikinci yüksek dağı, temiz havası ve şelaleleriyle \'oksijen barı\'dır.'),
  'linyi/pancake': ('Jianbing', 'İnce mısır gözlemesi \'jianbing\', Yimeng dağ halkının asırlık temel ekmeğidir.'),
  'cangzhou/lion': ('Demir Aslan', '1100 yıllık dev dökme demir aslan heykeli, şehrin gururlu nişanıdır.'),
  'cangzhou/martial': ('Dövüş Sanatları', 'Çin\'in \'wushu memleketi\'; ünlü ustalar ve dövüş okulları buradan çıktı.'),
  'cangzhou/canal': ('Büyük Kanal', 'Pekin-Hangzhou Büyük Kanalı şehrin içinden geçer; eski iskeleler hâlâ durur.'),
  'cangzhou/jujube': ('Altın Hünnap', 'İnce kabuklu tatlı \'altın iplik\' hünnabı, kuru meyvenin kralı sayılır.'),
  'nantong/textile': ('Tekstil Şehri', 'Çin\'in ev tekstili başkenti; pamuklu kumaşları dünya pazarlarına yayılır.'),
  'nantong/mountain': ('Langshan', 'Yangtze ağzında yükselen beş tepeli kutsal dağ, hac ve manzara yeridir.'),
  'nantong/kite': ('Banyao Uçurtması', 'Gökte uğuldayan düdüklü \'banyao\' uçurtmaları şehrin asırlık zanaatıdır.'),
  'nantong/school': ('Eğitim Öncüsü', 'Sanayici Zhang Jian burada Çin\'in ilk modern okul ve müzelerini kurdu.'),
  'taizhou/opera': ('Mei Lanfang', 'Pekin operasının efsanevi ustası Mei Lanfang\'ın memleketi burasıdır.'),
  'taizhou/tea': ('Sabah Çayı', 'Buğulama börek ve demli çayla başlayan \'zaocha\' kahvaltısı şehrin ritüelidir.'),
  'taizhou/boat': ('Qintong Kayık Şenliği', 'Baharda yüzlerce kürekçinin yarıştığı sandal şenliği nehri canlandırır.'),
  'taizhou/meatball': ('Aslan Başı Köfte', 'İri, yumuşacık domuz köftesi \'aslan başı\', Huaiyang mutfağının klasiğidir.'),
  'jinhua/ham': ('Jinhua Jambonu', 'Asırlık tuzlama yöntemiyle olgunlaşan kırmızı jambon, Çin\'in en ünlüsüdür.'),
  'jinhua/film': ('Hengdian Stüdyoları', 'Dünyanın en büyük açık hava film platosu; sayısız tarihî dizi burada çekilir.'),
  'jinhua/cave': ('Shuanglong Mağarası', 'Tekneyle alçak bir kaya kapısından girilen yeraltı mağarası nefes kesir.'),
  'jinhua/bridge': ('Eski Köprüler', 'Wuzhou\'nun kemerli taş köprüleri ve su kasabaları Jiangnan\'ın inceliğini taşır.'),
  'wuhu/park': ('Fangte Lunaparkı', 'Çin\'in en büyük tema parklarından biri; ailelere heyecan dolu günler sunar.'),
  'wuhu/ironart': ('Wuhu Demir Resmi', 'Demiri döverek yapılan zarif \'demir resim\' tabloları, 300 yıllık bir zanaattır.'),
  'wuhu/rice': ('Pirinç Limanı', 'Yangtze kıyısındaki şehir, tarih boyunca Çin\'in en büyük pirinç pazarıydı.'),
  'wuhu/river': ('Yangtze Limanı', 'İşlek nehir limanı, şehri Anhui\'nin denize açılan kapısı yapar.'),
  'huangshan/peak': ('Sarı Dağ', 'Granit zirveleri, bulut denizi ve eğri çamlarıyla Çin\'in en ünlü dağıdır.'),
  'huangshan/village': ('Hongcun Köyü', 'Su kanallı, beyaz duvarlı Hui köyleri UNESCO mirasıdır; resimlerden fırlamış gibidir.'),
  'huangshan/tea': ('Huangshan Maofeng', 'Sisli yamaçlarda toplanan tüylü uçlu yeşil çay, Çin\'in on ünlü çayından biridir.'),
  'huangshan/ink': ('Hui Mürekkep ve Mimari', 'Hui mürekkebi, oymalı ahşap evleri ve hat sanatı bölgenin kültür hazinesidir.'),
  'yichun/moon': ('Mingyue Dağı', '\'Parlak Ay\' dağı, sıcak su kaynakları ve teleferik manzaralarıyla ünlüdür.'),
  'yichun/spring': ('Selenyum Kaplıcaları', 'Nadir selenyumlu sıcak su kaynakları, şehri Çin\'in şifa-banyo merkezi yaptı.'),
  'yichun/zen': ('Zen Budizmi', 'Çin Zen mezheplerinin köklerini taşıyan dağ tapınakları sessizliğe çağırır.'),
  'yichun/rice': ('Pirinç Ovası', 'Verimli Yuan-He ovası, tarih boyunca Jiangxi\'nin tahıl ambarı olmuştur.'),
  'zhangzhou/narcissus': ('Nergis Çiçeği', 'Çin\'in en ünlü nergis soğanları burada yetişir; bahar şenliklerinin simgesidir.'),
  'zhangzhou/tulou': ('Hakka Tulou', 'Dev yuvarlak topraktan kale-evler UNESCO mirasıdır; bir köyü tek çatı altında toplar.'),
  'zhangzhou/banana': ('Tropik Meyveler', 'Muz, longan ve mandalina bahçeleri sıcak deltayı yıl boyu yeşertir.'),
  'zhangzhou/coast': ('Dongshan Adası', 'Altın kumlu plajları ve balıkçı köyleriyle ada, güney kıyısının incisidir.'),
  'beijing/great-wall': ('Çin Seddi', 'Kuzey sınırlarını korumak için yüzyıllar boyunca inşa edilen, 20.000 km\'yi aşan dünyanın en uzun savunma yapısı. Pekin\'e en yakın Badaling kesimi; taş basamakları, surları ve sırtlar boyunca uzanan gözetleme kuleleriyle en çok ziyaret edilen bölümdür.'),
  'beijing/temple': ('Cennet Tapınağı', 'Ming ve Qing imparatorlarının her yıl bol hasat için gökyüzüne dua ettiği kutsal tapınak kompleksi. Tek bir çivi kullanılmadan inşa edilen üç katmanlı yuvarlak mavi çatısı, Çin mimarisinin en tanınan simgelerinden biridir.'),
  'beijing/pagoda': ('Tianning Pagodası', 'Liao Hanedanı\'ndan kalma, yaklaşık 57 metre yüksekliğinde 13 katlı tuğla pagoda. Oymalı kabartmaları ve sekizgen gövdesiyle Pekin\'in ayakta kalan en eski yapılarından biridir ve şehrin bin yıllık geçmişine tanıklık eder.'),
  'beijing/opera': ('Pekin Operası', 'Şarkı, konuşma, dövüş sanatları ve akrobasinin birleştiği 200 yıllık geleneksel Çin sahne sanatı. Oyuncuların renkli yüz makyajı (lianpu) her karakterin kişiliğini anlatır: kırmızı sadakati, beyaz kurnazlığı simgeler.'),
};
